import { Router } from "express";
import { validateRequest } from "../middlewares/validate-request";
import {
  ChangePasswordSchema,
  DeleteAccountSchema,
  RequestOtpSchema,
  ResetPasswordSchema,
  SigninSchema,
  SignupSchema,
  UpdateProfileSchema,
  VerifyOtpSchema
} from "../validators/auth";
import {
  changePassword,
  deleteAccount,
  deleteAllUserSessions,
  deleteUserSession,
  forgotPassword,
  getUserProfile,
  getUserSessions,
  logoutUser,
  reactivateAccount,
  refreshToken,
  requestDeleteAccount,
  resetPassword,
  signinUser,
  signupUser,
  updateProfile,
  verifyResetPasswordOtp,
  verifyUser
} from "../controllers/auth.controller";
import { verifyAuthentication } from "../middlewares/verify-auth";
import { checkUserAccountRestriction } from "../middlewares/user-account-restriction";
import {
  changePasswordLimiter,
  deleteAccountLimiter,
  otpRequestLimiter,
  resetPasswordLimiter,
  signinRateLimiter,
  signupRateLimiter
} from "../middlewares/rate-limiter";
import upload from "../middlewares/upload-file";

const router = Router();

router.post(
  "/signup",
  validateRequest(SignupSchema),
  signupRateLimiter,
  signupUser
);

router.post("/verify-user", validateRequest(VerifyOtpSchema), verifyUser);

router.post(
  "/signin",
  validateRequest(SigninSchema),
  signinRateLimiter,
  signinUser
);

router.get("/profile", verifyAuthentication, getUserProfile);

router.patch(
  "/profile",
  upload.single("avatar"),
  validateRequest(UpdateProfileSchema),
  verifyAuthentication,
  checkUserAccountRestriction,
  updateProfile
);

router.get("/sessions", verifyAuthentication, getUserSessions);

router.delete(
  "/sessions",
  verifyAuthentication,
  checkUserAccountRestriction,
  deleteAllUserSessions
);

router.delete(
  "/sessions/:sessionId",
  verifyAuthentication,
  checkUserAccountRestriction,
  deleteUserSession
);

router.post("/refresh-token", refreshToken);

router.post(
  "/logout",
  verifyAuthentication,
  checkUserAccountRestriction,
  logoutUser
);

router.post(
  "/forgot-password",
  validateRequest(RequestOtpSchema.pick({ email: true })),
  otpRequestLimiter,
  forgotPassword
);

router.post(
  "/verify-reset-otp",
  validateRequest(VerifyOtpSchema),
  otpRequestLimiter,
  verifyResetPasswordOtp
);

router.post(
  "/reset-password",
  validateRequest(ResetPasswordSchema),
  resetPasswordLimiter,
  resetPassword
);

router.post(
  "/change-password",
  verifyAuthentication,
  validateRequest(ChangePasswordSchema),
  checkUserAccountRestriction,
  changePasswordLimiter,
  changePassword
);

router.post(
  "/account/request-delete",
  verifyAuthentication,
  validateRequest(SigninSchema.pick({ password: true })),
  checkUserAccountRestriction,
  deleteAccountLimiter,
  requestDeleteAccount
);

router.delete(
  "/account/delete",
  verifyAuthentication,
  validateRequest(DeleteAccountSchema),
  checkUserAccountRestriction,
  deleteAccountLimiter,
  deleteAccount
);

router.put("/account/reactivate", verifyAuthentication, reactivateAccount);

export default router;

import mongoose, { Document, Model, Schema } from "mongoose";

export interface IAvatar {
  public_id: string;
  url: string;
  size: number;
}

export interface IUser extends Document {
  _id: mongoose.Types.ObjectId;
  name: string;
  email: string;
  password?: string;
  role: "user" | "admin";
  isEmailVerified: boolean;
  lastLoginAt?: Date;
  failedLoginAttempts: number;
  lockUntil?: Date;
  avatar?: IAvatar;

  provider: "local" | "google" | "github";
  providerId?: string;

  isDeleted: boolean;
  deletedAt?: Date | null;
  reActivateAvailableAt?: Date | null;

  createdAt: Date;
  updatedAt: Date;
}

const userSchema = new Schema<IUser>(
  {
    name: {
      type: String,
      required: [true, "Name is required"],
      trim: true
    },
    email: {
      type: String,
      required: [true, "Email is required"],
      unique: true,
      lowercase: true,
      trim: true
    },
    password: {
      type: String,
      select: false,
      default: null
    },
    provider: {
      type: String,
      enum: ["local", "google", "github"],
      default: "local"
    },
    providerId: {
      type: String,
      default: null
    },
    role: {
      type: String,
      enum: ["user", "admin"],
      default: "user"
    },
    avatar: {
      public_id: String,
      url: String,
      size: Number
    },
    isEmailVerified: {
      type: Boolean,
      default: false
    },
    lastLoginAt: {
      type: Date
    },
    failedLoginAttempts: {
      type: Number,
      required: true,
      default: 0
    },
    lockUntil: {
      type: Date
    },
    isDeleted: {
      type: Boolean,
      default: false
    },
    deletedAt: {
      type: Date,
      default: null
    },
    reActivateAvailableAt: {
      type: Date,
      default: null
    }
  },
  {
    timestamps: true
  }
);

// Performance Indexes
userSchema.index({ provider: 1, providerId: 1 }); // Quick lookup for OAuth
userSchema.index({ role: 1 });
userSchema.index({ isDeleted: 1 }); // Optimized for soft-delete queries

const User: Model<IUser> =
  mongoose.models.User || mongoose.model<IUser>("User", userSchema);

export default User;

