import crypto from "node:crypto";

export function generateOTP(length: number = 6, ttlMinutes: number = 5) {
  const code = crypto
    .randomInt(0, Math.pow(10, length))
    .toString()
    .padStart(length, "0");

  const hashCode = crypto
    .createHash("sha256")
    .update(String(code))
    .digest("hex");

  const expiresAt = new Date(Date.now() + ttlMinutes * 60 * 1000).toISOString();

  return { code, hashCode, expiresAt };
}

export function generateHashedToken(token: string): string {
  return crypto.createHash("sha256").update(String(token)).digest("hex");
}

export function generateSecureToken(length: number = 32): string {
  return crypto.randomBytes(length).toString("hex");
}

export function verifyHashedToken(token: string, hashedToken: string): boolean {
  return (
    crypto.createHash("sha256").update(String(token)).digest("hex") ===
    hashedToken
  );
}

export function generateTokenAndHashedToken(id: string) {
  const cryptoSecret = process.env.CRYPTO_SECRET! || "secret";
  const token = crypto
    .createHmac("sha256", cryptoSecret)
    .update(String(id))
    .digest("hex");

  const hashedToken = crypto
    .createHash("sha256")
    .update(String(token))
    .digest("hex");
  return { token, hashedToken };
}

export function generateUUID(): string {
  return crypto.randomUUID();
}

import { Response } from "express";
import {
  ACCESS_TOKEN_EXPIRY,
  REFRESH_TOKEN_EXPIRY,
  SESSION_EXPIRY
} from "../constants/auth";
import env from "../configs/env";

const isProduction = env.NODE_ENV === "production";

export const COOKIE_OPTIONS = {
  httpOnly: true,
  secure: isProduction,
  sameSite: isProduction ? ("none" as const) : ("lax" as const),
  path: "/"
};

export function setAuthCookies(
  res: Response,
  accessToken: string,
  refreshToken: string,
  sessionId: string
) {
  setCookies(res, [
    {
      cookie: "accessToken",
      value: accessToken,
      maxAge: ACCESS_TOKEN_EXPIRY
    },
    {
      cookie: "refreshToken",
      value: refreshToken,
      maxAge: REFRESH_TOKEN_EXPIRY,
      path: "/api/v1/auth/refresh-token"
    },
    {
      cookie: "sid",
      value: sessionId,
      maxAge: SESSION_EXPIRY
    }
  ]);
}

export function clearAuthCookies(res: Response) {
  clearCookie(res, "accessToken");
  clearCookie(res, "refreshToken");
  clearCookie(res, "sid");
}

export function clearCookie(res: Response, cookie: string = "sid") {
  res.clearCookie(cookie, COOKIE_OPTIONS);
}

type Cookie = {
  cookie: string;
  value: string;
  maxAge: number;
  path?: string;
};

export function setCookies(res: Response, cookies: Cookie[]) {
  cookies.forEach(({ cookie, value, maxAge, path = "/" }) => {
    res.cookie(cookie, value, {
      ...COOKIE_OPTIONS,
      path,
      maxAge
    });
  });
}

